import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"SRP","description":"What SRP is, why it matters, how to apply, what you can gain, and what to prepare","frontmatter":{"lang":"en-US","title":"SRP","description":"What SRP is, why it matters, how to apply, what you can gain, and what to prepare"},"headers":[],"relativePath":"en/learn/extra/srp.md","filePath":"en/learn/extra/srp.md","lastUpdated":1774188210000}`),a={name:`en/learn/extra/srp.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/extra/srp.md for this page in Markdown format</div><h1 id="srp" tabindex="-1">SRP <a class="header-anchor" href="#srp" aria-label="Permalink to “SRP”">​</a></h1><p>SRP, short for Student Research Plan, is a SCUT-specific undergraduate research program at university level. If you participate and successfully complete the project, you can earn <strong>2 innovation credits</strong> (half-year SRP) or <strong>4 innovation credits</strong> (one-year SRP).</p><p>Undergraduate Innovation &amp; Entrepreneurship Platform (campus network required):</p><ul><li><a href="https://211.66.34.2/xm/CXCY/SCUT" target="_blank" rel="noreferrer">SCUT Undergraduate Innovation and Entrepreneurship Program Management System</a></li></ul><h2 id="project-requirements" tabindex="-1">Project Requirements <a class="header-anchor" href="#project-requirements" aria-label="Permalink to “Project Requirements”">​</a></h2><p>Each faculty member can supervise at most <strong>1 SRP project per year</strong>. Each project should have <strong>2-7 students</strong>. Priority is generally given to first- and second-year undergraduates. <strong>In principle, each student can only participate in one SRP project during their time at SCUT.</strong></p><h2 id="project-timeline" tabindex="-1">Project Timeline <a class="header-anchor" href="#project-timeline" aria-label="Permalink to “Project Timeline”">​</a></h2><p>April each year to March the next year.</p><h2 id="student-application" tabindex="-1">Student Application <a class="header-anchor" href="#student-application" aria-label="Permalink to “Student Application”">​</a></h2><p>Application period: <strong>2026-03-18 00:00 to 2026-03-22 24:00</strong></p><p>Applications are submitted online through the <strong>SCUT Undergraduate Innovation and Entrepreneurship Program Management System</strong>.</p><p>URLs:</p><p><a href="https://211.66.34.2/xm/CXCY/SCUT" target="_blank" rel="noreferrer">https://211.66.34.2/xm/CXCY/SCUT</a> (campus network required)</p><p><a href="https://211-66-34-2.webvpn.scut.edu.cn/xm/CXCY/SCUT" target="_blank" rel="noreferrer">https://211-66-34-2.webvpn.scut.edu.cn/xm/CXCY/SCUT</a> (WebVPN)</p><ul><li><p>Log in, then go to <strong>Personal Center -&gt; General</strong> and complete your email and phone information.</p></li><li><p>Go to <strong>Topic Management -&gt; Student Topic Selection</strong>, browse all available topics, choose one based on your interests and abilities, fill in the topic note, upload attachments if needed, then click <strong>Submit</strong>.</p></li><li><p>You can also check your applied topics and selection status in <strong>Topic Management -&gt; Student Topic Selection</strong>.</p></li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to “Tips”">​</a></h2><ul><li><p>Each student can select up to <strong>5 topics at the same time</strong>, but can only join <strong>1 final topic</strong>. If you apply to multiple topics, you will join the project of the first teacher who accepts you.</p></li><li><p>It is recommended to contact the teacher proactively after applying:</p><ul><li>Introduce yourself and ask about project requirements and expected tasks.</li><li>Popular projects usually involve interviews.</li><li>Some teachers do not rely on the system applications and only consider students who contact them by email/WeChat.</li></ul></li><li><p>SRP workload varies by project. Most projects are manageable for undergraduates: complete assigned tasks on time and submit the final report, and you can usually finish successfully and get innovation credits. A smaller number of projects may have much higher requirements/workload (for example, projects aiming at follow-up competitions such as National Innovation Program / Challenge Cup, or projects closely tied to a supervisor&#39;s real research with publication goals).</p></li><li><p>Read project descriptions carefully on the platform, and email the supervisor to confirm detailed expectations before deciding.</p></li></ul><h2 id="q-a" tabindex="-1">Q&amp;A <a class="header-anchor" href="#q-a" aria-label="Permalink to “Q&amp;A”">​</a></h2><p><strong>Q1</strong>: Why did a project disappear after I applied? <strong>A</strong>: In the topic selection page, change <strong>Selection Status</strong> from &quot;Not Selected&quot; to &quot;Selected&quot;.</p><p><strong>Q2</strong>: Is uploading attachments mandatory? What should I upload? <strong>A</strong>: Not mandatory. If you have files/certificates that highlight your strengths, upload them as attachments.</p><p><strong>Q3</strong>: How can I judge whether a project is &quot;easy&quot; or &quot;intense&quot;? <strong>A</strong>: Check from two angles:</p><ol><li>Ask senior students for recommendations.</li><li>Read the project&#39;s <strong>student requirements</strong>: if there are no strict requirements on specific skills or free time, workload may be lower. Use your own judgment.</li></ol><p><strong>Q4</strong>: Should I apply to projects in my own school/department or outside it? <strong>A</strong>: No strict requirement. Choose based on your preference. Your own school may feel more familiar, while some teachers welcome cross-school applicants.</p><p><strong>Q5</strong>: Can I apply multiple times during university? <strong>A</strong>: <strong>In principle</strong>, each student can only join <strong>1 SRP</strong> during their time at SCUT. Usually, next year&#39;s SRP application starts before the previous year&#39;s projects are closed, so applying in consecutive years is difficult. A possible strategy is once in freshman year and once in junior year.</p><p><strong>Q6</strong>: What if multiple teachers accept me? <strong>A</strong>: This typically does not happen. The system locks you into the first project that accepts you.</p><p><strong>Q7</strong>: What is the relationship between SRP and National Innovation Program projects? <strong>A</strong>: Some SRP projects continue into National Innovation Program projects, or were originally from that track. Joining this type of SRP may give you a chance to continue there.</p><p><strong>Q8</strong>: Will campus location be a problem for SRP projects? <strong>A</strong>: Usually group meetings are online. If a project does not explicitly require offline meetings or lab duty, campus location is usually not a major issue.</p><p><strong>Q9</strong>: How many students are recruited per SRP project? <strong>A</strong>: Usually <strong>2-7</strong> students.</p><p><strong>Q10</strong>: Does SRP conflict with joining a lab? <strong>A</strong>: Generally no.</p>`,30)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};